INSERT INTO `article` VALUES (2,'<p><strong>Gabriel Castr</strong></p>\r\n',2,'Gabriel Castro Legal',2,1,'','2014-01-08 11:08:52'),(15,'<p>Fotos do Semin&aacute;rio de Encerramento de Exerc&iacute;cio 2013.<br />\r\nFotos capturadas pelo setor de Comunica&ccedil;&atilde;o.</p>\r\n',52,'SeminÃÂ¡rio de Encerramento de ExercÃÂ­cio 2013',2,2,'{\"fotos\":[{\"nome\":null,\"id\":\"7962a5b4acace560cdbf84a7add572c1\"},{\"nome\":null,\"id\":\"dcb2fb2d8382b9278870e471ceaf6986\"},{\"nome\":null,\"id\":\"588c798dccf5d149688969a8f653dbba\"},{\"nome\":null,\"id\":\"0c12d178f76dc801d3c1e3aab1cb55ef\"},{\"nome\":null,\"id\":\"2b7ccc32e5f7028917069a09d9814288\"},{\"nome\":null,\"id\":\"04dddc02066d841547d424bc401f7f9c\"},{\"nome\":null,\"id\":\"e7436630120a05a9ea759445271427dc\"},{\"nome\":null,\"id\":\"a63e6e2a7dc73d8e6907898105dc3e9d\"},{\"nome\":null,\"id\":\"c570c6ddc7a6ae534b733e553a630503\"},{\"nome\":null,\"id\":\"4d638a57e585140d0ddd694b6582b406\"},{\"nome\":null,\"id\":\"c73aa0a84870e7ddd022b5b5e88b9fb4\"},{\"nome\":null,\"id\":\"7e9e2d6b977b97ed20e19d16ebf383e4\"},{\"nome\":null,\"id\":\"e318fb8b1ab6a46d41dcfa6248f129c0\"},{\"nome\":null,\"id\":\"e1b0ec1d86b83a8059c3a890750046d7\"},{\"nome\":null,\"id\":\"442bd76a875c59c5172c9830d44f3b1f\"},{\"nome\":null,\"id\":\"343a7e99daaa3650a9147d9e2f64ea5a\"},{\"nome\":null,\"id\":\"31687cfb3ae3f2d9df13645c406aaa00\"},{\"nome\":null,\"id\":\"93bfb48417b09bb49c6e7a8659247b23\"},{\"nome\":null,\"id\":\"e9489d6c0d354fb65fcf147b4be0a824\"},{\"nome\":null,\"id\":\"c2beb53b345b4f8f6c1e82572e982cad\"},{\"nome\":null,\"id\":\"66a2ffc115758e63d19ffd741f31e577\"},{\"nome\":null,\"id\":\"0a3fda87d521b0b1b62d5e7894ac68ad\"},{\"nome\":null,\"id\":\"8d38a40287ef7b51e181efbe0cb4235a\"},{\"nome\":null,\"id\":\"8c0d79dda3e960b72865ec21495621e5\"},{\"nome\":null,\"id\":\"a33f12f5cde4d69b2a62306085c8cbc3\"},{\"nome\":null,\"id\":\"c79a8b41d507df709ee38737a6793e0a\"},{\"nome\":null,\"id\":\"44b823447c16e5d6cf536adcad03b13b\"},{\"nome\":null,\"id\":\"290330f07809c0b6c2461b15661a1d9f\"},{\"nome\":null,\"id\":\"008e9c8175666b1e441d64f4c625a4e8\"},{\"nome\":null,\"id\":\"200c5fb6bb4f16be6de0dfef42ee62ee\"},{\"nome\":null,\"id\":\"75714e5b8327e147fbaae0422c4fd800\"},{\"nome\":null,\"id\":\"dbde5576c03a3992ce6d8d65d868008b\"},{\"nome\":null,\"id\":\"729320124fefa65f8de2b9ac79e5220b\"},{\"nome\":null,\"id\":\"0e15bd1bf761ea6c662e2143d2972e71\"},{\"nome\":null,\"id\":\"aec41ad78edcb5eae2a1f8c795afa741\"},{\"nome\":null,\"id\":\"31695fd99aedfaf71653b2429accdf6f\"},{\"nome\":null,\"id\":\"4de77d9126f9e68181116879f456ace3\"},{\"nome\":null,\"id\":\"546333ebb17695ab6594712e89c4d408\"},{\"nome\":null,\"id\":\"4bff96db879df2009da85f97f39da94a\"},{\"nome\":null,\"id\":\"79c3910caa00991db7703b7d008753ff\"},{\"nome\":null,\"id\":\"fcff96567fa55d3b6176d8d63f9bc308\"},{\"nome\":null,\"id\":\"ed5bc83af1b7140a5d2d7883d408ac20\"},{\"nome\":null,\"id\":\"1f3093221915126c1b3ac16bc9a99706\"},{\"nome\":null,\"id\":\"36b159b8b537af513f8eb4f9b213d731\"},{\"nome\":null,\"id\":\"05a75cd1ac085428fcbcd57546fc405d\"},{\"nome\":null,\"id\":\"deb303e42f4e7ddb2fd1396da6d7f5c3\"},{\"nome\":null,\"id\":\"dcc5a97a0a72e2a4b44bb62aa6baa3a4\"},{\"nome\":null,\"id\":\"1038cfd11a0af57969328b18efa77d82\"},{\"nome\":null,\"id\":\"0e6ed97e967ccec5f4270ced774ed32b\"},{\"nome\":null,\"id\":\"87b7eef9c68c4cf0db979dc6677c41a8\"},{\"nome\":null,\"id\":\"dd9ba2756b831f6159457a8d483bf456\"},{\"nome\":null,\"id\":\"aa949c290d83362c36e84695e8090f54\"}]}','2014-01-14 10:13:24'),(17,'<p>Entre os dias 14 e 16 de janeiro, o pesquisador Leonardo Luiz Lyrio da Silveira e o t&eacute;cnico Jefferson Luiz Camargo estiveram na cidade de Barroso &ndash; MG, a convite da Cimec, empresa do ramo de cimento e concreto, para estabelecer parceria e coopera&ccedil;&atilde;o em pesquisa e inova&ccedil;&atilde;o na &aacute;rea de rochas ornamentais.&nbsp; Na ocasi&atilde;o, visitaram a empresa Petraminas, pertencente ao grupo Cimec. A visita teve como objetivo principal verificar poss&iacute;veis melhorias t&eacute;cnicas. No per&iacute;odo em que os t&eacute;cnicos estiveram em Barroso, foi poss&iacute;vel visitar as pedreiras de rochas ornamentais e o parque de processamento da referida empresa. Como desdobramento, o CETEM dever&aacute; realizar um estudo completo sobre as melhores situa&ccedil;&otilde;es de polimento para os m&aacute;rmores que a empresa produz no que tange &agrave; otimiza&ccedil;&atilde;o do processo.&nbsp;</p>\r\n',52,'CETEM estuda parceria na ÃÂ¡rea de rochas ornamentais com a empresa Cimec',2,1,'null','2014-02-13 16:27:16'),(18,'<h3 style=\"text-align:justify\"><span style=\"font-family:calibri,sans-serif; font-size:11pt\">O Coordenador da CATE, Francisco Hollanda,&nbsp;esteve em Teresina,&nbsp;no &uacute;ltimo dia 31 de janeiro, para tratar de assuntos relacionados ao projeto APL-Opala. Na ocasi&atilde;o participou de reuni&atilde;o com o CPRM (Servi&ccedil;o Geol&oacute;gico do Brasil), o DNPM (<a href=\"http://www.google.com.br/url?sa=t&amp;rct=j&amp;q=&amp;esrc=s&amp;source=web&amp;cd=1&amp;cad=rja&amp;ved=0CCkQFjAA&amp;url=http%3A%2F%2Fwww.redeaplmineral.org.br%2Fbanco_apls%2Finstituicoes%2Fdepartamento-nacional-de-producao-mineral-21o-distrito-pi%2F&amp;ei=AXLqUpv4LuHhyQHThYGACA&amp;usg=AFQjCNG3fCeB-Lb_SP1X8ge0QkdY-tgsdA&amp;sig2=1wIxnSWC31B4dIZEVb6iMQ&amp;bvm=bv.60444564,d.aWc\">Departamento Nacional de Produ&ccedil;&atilde;o Mineral</a>), o SEDET (Secret&aacute;ria de Desenvolvimento Econ&ocirc;mico e Tecnol&oacute;gico do Piau&iacute;) e a FADEX (Funda&ccedil;&atilde;o Cultural e de Fomento a Pesquisa, Ensino e Extens&atilde;o),&nbsp;que s&atilde;o parceiros do projeto atualmente em execu&ccedil;&atilde;o. No dia 03 de fevereiro, esteve em Recife e em Campina Grande para participar de reuni&otilde;es sobre a implanta&ccedil;&atilde;o dos projetos Entidades Associadas (EA) na UFPE (Universidade Federal de Pernambuco) e na UFCG (Universidade Federal de Campina Grande). Entre os dias 04 e 06 de fevereiro, visitou &aacute;reas mineradas&nbsp;da Prov&iacute;ncia&nbsp;Pegmat&iacute;tica da Borborema/Serid&oacute;, nos Estados da Para&iacute;ba e do Rio Grande do Norte,&nbsp;que fazem parte do escopo&nbsp;do projeto da EA-UFCG.&nbsp;</span></h3>\r\n',52,'APL-Opala: Pesquisador do CETEM participa de reuniÃÂµes com diversas entidades',2,1,'null','2014-02-13 16:28:30'),(19,'<p style=\"text-align:justify\"><img alt=\"\" src=\"/media/img/imagens/images/LibreOffice.png\" style=\"float:left; height:89px; width:300px\" />O CETEM, em conformidade com as <a href=\"http://www.softwarelivre.gov.br/planejamento-anteriores/diretrizes-da-implementacao-do-software-livre-no-governo-federal-2003/\">diretrizes </a>para ado&ccedil;&atilde;o de Software Livre do Governo Federal, est&aacute; em processo de ado&ccedil;&atilde;o do LibreOffice, uma suite de escrit&oacute;rio livre compat&iacute;vel com as principais alternativas comerciais do mercado, oferecendo todas as fun&ccedil;&otilde;es esperadas de uma suite profissional: editor de textos, planilha, apresenta&ccedil;&atilde;o, editor de desenhos e banco de dados.</p>\r\n\r\n<p style=\"text-align:justify\">O SEIN migrou seus microcomputadores do MS Office para o LibreOffice, e o SMPI-Compras est&aacute; realizando a migra&ccedil;&atilde;o, com previs&atilde;o de treinamento para os usu&aacute;rios em Fevereiro/2014. Para maiores informa&ccedil;&otilde;es, consulte a p&aacute;gina oficial da comunidade <a href=\"http://pt-br.libreoffice.org/home/\">LibreOffice</a>, ou diretamente a <a href=\"https://wiki.documentfoundation.org/Documentation/pt-br/Tradu%C3%A7%C3%A3o#Guia_do_Iniciante_LO_4.0.X\">documenta&ccedil;&atilde;o </a>(em processo de tradu&ccedil;&atilde;o) para a &uacute;ltima vers&atilde;o.</p>\r\n',1,'CETEM passa a adotar o LibreOffice',2,1,'null','2014-02-14 15:49:30'),(20,'<p style=\"text-align: justify;\">O servidor Fl&aacute;vio Balduino de Brito, anteriormente lotado no SERH (Servi&ccedil;o de Recursos Humanos), passou, a partir do m&ecirc;s de fevereiro, a exercer suas fun&ccedil;&otilde;es na CPGI (Coordena&ccedil;&atilde;o de Planejamento, Gest&atilde;o e Inova&ccedil;&atilde;o). Flavio est&aacute; trabalhando no desenvolvimento do Programa Gest&atilde;o pela Qualidade do CETEM.</p>\r\n',52,'Servidor ÃÂ© removido do SERH e integra a equipe da CPGI ',2,1,'null','2014-02-17 15:38:45'),(21,'<p style=\"text-align: justify;\">O tecnologista Ot&aacute;vio da Fonseca Martins Gomes participa do Congresso promovido anualmente pela <em>The Minerals, Metals and Materials Society</em>, o TMS 2014. O evento, que j&aacute; est&aacute; em sua 143a. edi&ccedil;&atilde;o, espera reunir mais de quatro mil pessoas entre empres&aacute;rios, engenheiros, cientistas e outros profissionais das ind&uacute;strias mineral, metal&uacute;rgica e de materiais, em S&atilde;o Diego, Calif&oacute;rnia, EUA, entre os dias 16 e 20 de fevereiro. Durante o evento o tecnologista apresentar&aacute; o trabalho &quot;C<em>haracterization of Particle Damage and Surface Exposure of a Copper Ore Processed by Jaw Crusher, HPGR and Electro-dynamic Fragmentation</em>&quot; de sua autoria em parceria com a Dra. D&eacute;bora Oliveira e o Dr. Luis Sobral, ambos do CETEM, e com o Dr. Eric Pirard da Universidade de Liege (B&eacute;lgica). Ot&aacute;vio participar&aacute;, ainda, como co-autor do trabalho &quot;<em>Characterization of Printed Circuit Boards from Scrap Printers</em>&quot; em uma colabora&ccedil;&atilde;o com pesquisadores da Universidade de Liege e da USP.</p>\r\n',52,'TMS 2014: Tecnologista apresenta trabalho ',2,1,'null','2014-02-17 15:39:54'),(22,'<p style=\"text-align: justify;\">A pesquisadora da COAM, Lilian Irene Dias da Silva ir&aacute;, entre os dias 02 e 06 de mar&ccedil;o, aos Estados Unidos para participar do congresso e exposi&ccedil;&atilde;o &ldquo;PITTCON 2014 Conference &amp; Expo&rdquo;, na cidade de Chicago. A ida &agrave; exposi&ccedil;&atilde;o &eacute; fruto do pr&ecirc;mio obtido pela pesquisadora no XVII ENQA &ndash; Encontro Nacional de Qu&iacute;mica Anal&iacute;tica, que ocorreu em outubro do ano passado, em Belo Horizonte. O trabalho intitulado &ldquo;Biodisponibilidade de metais em MP<sub>10</sub> da regi&atilde;o metropolitana da cidade do Rio de Janeiro (RMCRJ)&rdquo;, de autoria de L&iacute;lian Irene D. da Silva, L&iacute;dia Yokoyama, Lucas B. Maia,&nbsp;Maria In&ecirc;s C. Monteiro, Fernanda Veronesi M. Pontes, Manuel C. Carneiro e Arnaldo Alcover Neto, obteve o pr&ecirc;mio de melhor trabalho em p&ocirc;ster do evento. A Pittcon &eacute; a maior e mais abrangente confer&ecirc;ncia e exposi&ccedil;&atilde;o anual de ci&ecirc;ncia laboratorial do mundo, extrapolando a qu&iacute;mica anal&iacute;tica e a espectroscopia para incluir todos aqueles que &quot;analisam ou testam as propriedades qu&iacute;micas ou bil&oacute;gicas de compostos ou mol&eacute;culas, ou quem administra esses cientistas&quot;. S&atilde;o esperadas mais de 18 mil pessoas, provenientes da ind&uacute;stria, universidades e governos, de mais de 90 pa&iacute;ses.</p>\r\n',52,'Pesquisadora participa de conferÃÂªncia nos EUA ',2,1,'null','2014-02-17 15:40:48'),(23,'<p>Informamos que nesta sexta (21/02), excepcionalmente, a biblioteca estar&aacute; fechada a partir das 12 hs, voltando ao atendimento normal na segunda, 24/02.</p>\r\n\r\n<p>Agradecemos a compreens&atilde;o, e estamos &agrave; disposi&ccedil;&atilde;o para o esclarecimento de eventuais d&uacute;vidas.</p>\r\n\r\n<p>Obrigado.</p>\r\n',1,'Biblioteca',2,1,'null','2014-02-19 14:40:18'),(24,'<p style=\"text-align: justify;\">O Coordenador da CATE, Dr. Francisco Hollanda, viajar&aacute; para o interior do Cear&aacute; juntamente com o Professor da UFC (Universidade Federal do Cear&aacute;) Ge&oacute;logo Dr. Jos&eacute; Nogueira, no per&iacute;odo de 26 de fevereiro a 01 de mar&ccedil;o, para fazer uma visita t&eacute;cnica aos pegmatitos das prov&iacute;ncias que abrangem o Sert&atilde;o Central do estado, localizados principalmente nos munic&iacute;pios de Solon&oacute;pole, Berilandia, Quixeramobim e Banabui&uacute;.</p>\r\n\r\n<p style=\"text-align: justify;\">A visita a essa regi&atilde;o &eacute; uma das metas do projeto EA-UFCG (Entidades Associadas &ndash; Universidade Federal de Campo Grande) e visa fazer um diagn&oacute;stico da situa&ccedil;&atilde;o atual da explora&ccedil;&atilde;o mineral dos pegmatitos da Prov&iacute;ncia no Cear&aacute; que cont&eacute;m pedras preciosas, al&eacute;m dos minerais de Feldspatos, Quartzos e Micas.</p>\r\n\r\n<p style=\"text-align: justify;\">Na oportunidade ser&atilde;o realizadas coletas de amostras para desenvolver a caracteriza&ccedil;&atilde;o tecnol&oacute;gica e os ensaios de beneficiamento do min&eacute;rio visando o aproveitamento integral dos pegmatitos que tenham potencial de reservas para a lavra. Na parte referente &agrave;s pedras preciosas, ser&aacute; feita uma an&aacute;lise preliminar do que ainda existe com a explora&ccedil;&atilde;o desse bem mineral para que o CETEM possa fazer o estudo de caracteriza&ccedil;&atilde;o tecnol&oacute;gica.</p>\r\n',52,'Coordenador vai ao CearÃÂ¡ para visita tÃÂ©cnica ',2,1,'null','2014-02-20 10:55:04'),(25,'<p style=\"text-align: justify;\">A servidora Antonieta Middea obteve no dia 11 de fevereiro o t&iacute;tulo de doutora pela Universidade Federal do Rio de Janeiro &ndash; UFRJ.&nbsp; A tese intitulada &quot;Obten&ccedil;&atilde;o e caracteriza&ccedil;&atilde;o de nanocomp&oacute;sito magn&eacute;tico &agrave; base de paligorsquita/poliestireno&quot; foi apresentada no Instituto de Macromol&eacute;culas Professora Eloisa Mano &ndash; IMA e aprovada de forma un&acirc;nime. A orienta&ccedil;&atilde;o da tese foi da Dra Luciana Spinelli Ferreira (IMA/UFRJ), Dr. Fernando Gomes de Souza Jr (IMA/UFRJ) e Dr. Reiner Neumann (CETEM/MCTI).</p>\r\n\r\n<p style=\"text-align: justify;\">Foram sintetizados e caracterizados dois produtos, testados na remo&ccedil;&atilde;o de contaminantes org&acirc;nicos de afinidades diferentes, por &aacute;gua e por &oacute;leo, e com grande efici&ecirc;ncia. A principal diferen&ccedil;a em rela&ccedil;&atilde;o a outros produtos com a mesma aplica&ccedil;&atilde;o &eacute; que estes podem ser recuperados com uma simples separa&ccedil;&atilde;o magn&eacute;tica, o que abre caminho para o seu emprego em escala industrial.</p>\r\n',52,'Pesquisadora obtÃÂ©m tÃÂ­tulo de doutorado',2,1,'null','2014-02-20 10:57:15'),(26,'<p style=\"text-align: justify;\">A Apple divulgou uma falha de seguran&ccedil;a no sistema iOS (para iPhones e iPads) e no OS X (Mac).</p>\r\n\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">A falha no iOS pode ser corrigida atualizando o sistema para a vers&atilde;o 7.0.6 ou 6.1.6 (para sistemas mais antigos). Para o OS X, ainda n&atilde;o foi divulgada uma corre&ccedil;&atilde;o. Como solu&ccedil;&atilde;o tempor&aacute;ria, recomendamos o uso do Mozilla Firefox ou Google Chrome para Mac, ao inv&eacute;s do Safari.</p>\r\n\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">Maiores detalhes sobre a vulnerabilidade podem ser lidas <a href=\"http://gizmodo.uol.com.br/apple-bug-ssl/\">aqui</a>.</p>\r\n\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">Em caso de d&uacute;vidas ou se necessitar de aux&iacute;lio, por favor entre em contato com nosso suporte, pelo ramal 7301 ou e-mail sein-suporte@cetem.gov.br.</p>\r\n',1,'AtualizaÃÂ§ÃÂ£o de SeguranÃÂ§a - Apple',2,1,'null','2014-02-25 07:58:31'),(27,'<p style=\"text-align:justify\">A Apple acaba de liberar a atualiza&ccedil;&atilde;o de seguran&ccedil;a para o Safari e OS X.</p>\r\n\r\n<p style=\"text-align:justify\">Saiba mais <a href=\"http://support.apple.com/kb/HT1222?viewlocale=pt_BR\">aqui</a>.</p>\r\n\r\n<p>&nbsp;</p>\r\n',1,'AtualizaÃÂ§ÃÂ£o de SeguranÃÂ§a - Apple [Atualizado]',2,1,'null','2014-02-25 16:36:53'),(28,'<p>A equipe de divulga&ccedil;&atilde;o institucional ir&aacute; divulgar ao t&eacute;rmino de cada m&ecirc;s relat&oacute;rio sucinto das not&iacute;cias sobre o CETEM publicadas em ve&iacute;culos de grande circula&ccedil;&atilde;o, sites, jornais e revistas especializados.&nbsp;<span style=\"line-height:1.6em\">Nos meses de janeiro e fevereiro de 2014, foram publicadas as seguintes not&iacute;cias:</span></p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140224%20-%20entrevistaFLins%20-%20Ibram.pdf\" target=\"_blank\">CETEM desenvolve tecnologias para a atividade sustent&aacute;vel no setor mineral</a><br />\r\nSite do IBRAM - 24/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140224%20-%20entrevistaFLins%20-%20petronot%C3%ADcias.pdf\" target=\"_blank\">CETEM desenvolve tecnologias para a atividade sustent&aacute;vel no setor mineral</a><br />\r\nPetronot&iacute;cias - 24/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140220%20-%20rebolo-ecoabrasivo-IBRAM.pdf\" target=\"_blank\">Tecnologia mineral inovadora &eacute; apresentada em feira internacional</a><br />\r\nSite do IBRAM - 19/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140218%20-%20vitoria%20stone%20fair%20-%20revista%20minerios.pdf\" target=\"_blank\">CETEM apresenta tecnologia mineral inovadora</a><br />\r\nMin&eacute;rios &amp; Minerales - 18/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140218%20-%20vitoria%20stone%20fair%20-%20mining.pdf\" target=\"_blank\">CETEM apresenta tecnologia mineral inovadora na 37&ordf; Feira Internacional do M&aacute;rmore e Granito, em Vit&oacute;ria</a><br />\r\nIn the Mine - 18/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140217%20-%20vitoriastonefair%20-%20portalMCTI.pdf\" target=\"_blank\">CETEM apresenta tecnologia inovadora em feira internacional</a><br />\r\nPortal do MCTI - 17/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140217%20-%20vitoriastonefair%20-%20jornaldaciencia.pdf\" target=\"_blank\">CETEM apresenta tecnologia mineral inovadora na 37&ordf; Feira Internacional do M&aacute;rmore e Granito, em Vit&oacute;ria</a><br />\r\nJornal da Ci&ecirc;ncia (e-mail 4896) - 17/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140217%20-%20vitoria%20stone%20fair%20-%20jornal%20brasil.pdf\" target=\"_blank\">CETEM apresenta tecnologia inovadora em feira internacional</a><br />\r\nJornal Brasil Online - 17/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140217%20-%20rebolo%20-%20portal%20NMB.pdf\" target=\"_blank\">Rebolo ecoabrasivo &eacute; alternativa para polimento de chapas de rochas ornamentais</a><br />\r\nPortal Not&iacute;cias de Minera&ccedil;&atilde;o Brasil - 17/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140217%20-%20cetem-pi%20-%20geofisica-brasil.pdf\" target=\"_blank\">CETEM de Teresina (PI) ser&aacute; inaugurado em breve</a><br />\r\nSite Geof&iacute;sica Brasil - 17/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/20140203-cristo-redentor-odia.pdf\" target=\"_blank\">IPHAN vai &#39;ca&ccedil;ar&#39; pedra pare revestir o Cristo Redentor</a><br />\r\nJornal O Dia - 03/02/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/2014jan-fev%20-%20workshoprochas%20-%20rochasdequalidade.pdf\" target=\"_blank\">Workshop discute o futuro do setor de rochas fluminense</a><br />\r\nRevista Rochas de Qualidade, edi&ccedil;&atilde;o n&ordm; 234 - jan./fev. de 2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/fevereiro/2014jan-fev%20-%20seminarioAPL%20-%20rochasdequalidade.pdf\" target=\"_blank\">Vit&oacute;ria - ES sedia X Semin&aacute;rio Nacional de Arranjos Produtivos Locais de Base Mineral</a><br />\r\nRevista Rochas de Qualidade, edi&ccedil;&atilde;o n&ordm; 234 - jan./fev. de 2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/clipping/2014/janeiro/20140120%20-%20terras-raras-Liberation.pdf\" target=\"_blank\">Au Br&eacute;sil, le retour aux terres rares</a><br />\r\nJornal Lib&eacute;ration - 20/01/2014</p>\r\n\r\n<p>As mat&eacute;rias acima listadas est&atilde;o dispon&iacute;veis externamente em nosso site: <a href=\"http://www.cetem.gov.br/comunicacao/clipping\">http://www.cetem.gov.br/comunicacao/clipping </a>&nbsp;</p>\r\n',51,'CETEM na mÃÂ­dia: balanÃÂ§o de janeiro e fevereiro',2,1,'null','2014-02-28 10:24:53'),(29,'<p>Informamos que dia 07/03/2014, no per&iacute;odo das 17 &agrave;s 18 hs, realizaremos manuten&ccedil;&atilde;o no firewall do CETEM.</p>\r\n\r\n<p>Desse modo, tanto o acesso &agrave; internet quanto o acesso externo aos servi&ccedil;os (site do CETEM, webmail, Citrix) poder&atilde;o estar indispon&iacute;veis nesse per&iacute;odo.</p>\r\n\r\n<p>Em caso de d&uacute;vidas por favor entrem em contato com nosso suporte, pelo ramal 7301 ou e-mail <a href=\"mailto:sein-suporte@cetem.gov.br\">sein-suporte@cetem.gov.br</a>.</p>\r\n\r\n<p>Obrigado.</p>\r\n',1,'ManutenÃÂ§ÃÂ£o - Firewall',2,1,'null','2014-03-06 10:51:31'),(31,'<p style=\"text-align:justify\">O CETEM e a <em>Cooperativa Coopquitungo Cooperando e Reciclando o Rio Ltda</em> firmaram Termo de Compromisso para o recolhimento dos res&iacute;duos recicl&aacute;veis produzidos pelo Centro.&nbsp; A <em>Coopquitungo</em> foi a &uacute;nica cooperativa a manifestar interesse em participar da sele&ccedil;&atilde;o promovida pelo Edital de Chamamento P&uacute;blico N.&ordm; 001/2013, lan&ccedil;ado no segundo semestre de 2013, e cumpriu todas as exig&ecirc;ncias impostas pelo referido documento. Todo o trabalho foi conduzido pela Comiss&atilde;o de Coleta Seletiva Solid&aacute;ria (CCSS), institu&iacute;da pela Portaria CETEM n&ordm; 40/2013, com apoio da COAD. Com o estabelecimento do acordo, o CETEM encontra-se em conformidade com o Decreto n&deg; 5940/2006, que determina que todo o res&iacute;duo recicl&aacute;vel descartado pelos &oacute;rg&atilde;os e entidades da administra&ccedil;&atilde;o p&uacute;blica federal direta e indireta, deve ser destinado &agrave;s associa&ccedil;&otilde;es e cooperativas dos catadores de materiais recicl&aacute;veis, com vistas &agrave; promo&ccedil;&atilde;o da inclus&atilde;o social. Na primeira coleta, realizada no dia 27 de fevereiro de 2014, foram doados ou recolhidos 778 quilos de papel&atilde;o e 25 quilos de pl&aacute;stico. A CCSS disp&otilde;e de uma conta de e-mail para d&uacute;vidas e sugest&otilde;es: <a href=\"mailto:coleta-seletiva@cetem.gov.br\">coleta-seletiva@cetem.gov.br</a>.</p>\r\n',52,'CETEM firma termo para recolhimento de resÃÂ­duos reciclÃÂ¡veis ',2,1,'null','2014-03-13 11:03:05'),(32,'<p style=\"text-align: justify;\">Nos dias 11 e 12 de fevereiro, os engenheiros Hudson Couto, Paulo Braga e Silvia Fran&ccedil;a, pesquisadores da COPM, realizaram visitas t&eacute;cnicas &agrave; refinaria da CBA &ndash; Companhia Brasileira de Alum&iacute;nio (Votorantim Metais), no munic&iacute;pio de Alum&iacute;nio-SP e ao Laborat&oacute;rio de Processos e Planta Piloto da &aacute;rea de Tecnologia de Processos e Inova&ccedil;&atilde;o (PTI) da empresa Metso, em Sorocaba-SP. A visita &agrave; CBA teve como objetivo conhecer e discutir a rota do processo de produ&ccedil;&atilde;o do auxiliar de filtra&ccedil;&atilde;o TCA (tri-c&aacute;lcio aluminato), visando adquirir novos conhecimentos sobre este processo, do qual os pesquisadores envolvidos possuem atualmente um projeto em desenvolvido sobre o tema no CETEM. A visita &agrave; Metso teve como foco a apresenta&ccedil;&atilde;o de projetos do CETEM e discuss&atilde;o de possibilidades de parcerias entre a empresa e o Centro.</p>\r\n',52,'Engenheiros do CETEM realizam visitas tÃÂ©cnicas visando adquirir conhecimentos sobre o TCA',2,1,'null','2014-03-13 11:04:06'),(33,'<p>A Microsoft lan&ccedil;ou a vers&atilde;o gratuita do OneNote para diversas plataformas.</p>\r\n\r\n<p>Saiba mais em: <a href=\"http://gizmodo.uol.com.br/onenote-gratuito-mac-windows/\">http://gizmodo.uol.com.br/onenote-gratuito-mac-windows/</a>, ou acesse diretamente <a href=\"http://www.onenote.com\">www.onenote.com</a>.</p>\r\n\r\n<p>Caso deseje instalar o aplicativo, consulte nosso suporte pelo e-mail sein-suporte@cetem.gov.br ou pelo ramal 7301.</p>\r\n',1,'Microsoft lanÃÂ§a OneNote gratuito.',2,1,'null','2014-03-18 09:51:42'),(34,'<p>Informamos que os certificados digitais, que fornecem a criptografia SSL para os sites da Intranet e do servidor de Pesquisas, expiram dias 21 e 22/03, respectivamente.</p>\r\n\r\n<p>Como &eacute; um ambiente beta, ainda n&atilde;o colocamos o certificado digital do ICP-BR definitivo, que est&aacute; em processo de aquisi&ccedil;&atilde;o..</p>\r\n\r\n<p>Com isso, aparecer&aacute; uma mensagem de certificado inv&aacute;lido, basta aceitar o mesmo e continuar. A conex&atilde;o ser&aacute; criptografada com SSL.</p>\r\n\r\n<p>Em caso de d&uacute;vidas, por favor entrem em contato com nosso suporte, pelo e-mail <a href=\"mailto:sein-suporte@cetem.gov.br\">sein-suporte@cetem.gov.br</a> ou pelo ramal 7301.</p>\r\n',1,'Certificados Digitais - Intranet e Pesquisas',2,1,'null','2014-03-19 19:48:29'),(35,'<p style=\"text-align: justify;\">A CPGI conta a partir de mar&ccedil;o com dois novos servidores, Renata Queiroz Affonso, transferida do MCTI, e Marcelo Biagi, que retorna ao CETEM ap&oacute;s um per&iacute;odo de afastamento.&nbsp; Renata se juntou a equipe do NIT e ser&aacute; a respons&aacute;vel pela elabora&ccedil;&atilde;o de editais e toda a documenta&ccedil;&atilde;o jur&iacute;dica.&nbsp; Ainda prestar&aacute; aux&iacute;lio no fechamento dos termos de coopera&ccedil;&atilde;o, de parcerias com empresas e ICT&rsquo;s. Marcelo ficar&aacute; respons&aacute;vel por auxiliar em projetos de comunica&ccedil;&atilde;o relacionados ao site do CETEM e manuten&ccedil;&atilde;o da mala direta institucional.</p>\r\n\r\n<p style=\"text-align: justify;\">J&aacute; o SERH (Servi&ccedil;o de Recursos Humanos) passa a contar com o servidor Bruno Medeiros, anteriormente lotado no SEOF (Servi&ccedil;o de Or&ccedil;amento, Finan&ccedil;as e Contabilidade), diante da iminente sa&iacute;da&nbsp;da servidora Nathalia Nascimento Pinheiro, que foi aprovada em concurso para o IBGE, carreira de analista. Bruno ir&aacute; responder, inicialmente, pelos processos de pens&atilde;o, aposentadoria e abono de perman&ecirc;ncia.</p>\r\n',52,'MudanÃÂ§a de servidores na CPGI e no SERH',2,1,'null','2014-03-28 14:24:32'),(36,'<p style=\"text-align: justify;\">O ge&oacute;logo Dr. Jurgen Schnellrath visitou a empresa Geometa Ltda, no per&iacute;odo de 19 a 21 de mar&ccedil;o, em Governador Valadares, Minas Gerais. A visita ocorreu no &acirc;mbito do trabalho de caracteriza&ccedil;&atilde;o de uma nova ocorr&ecirc;ncia de esmeraldas em Minas Gerais, mais especificamente no munic&iacute;pio de Conselheiro Pena, trabalho esse feito pelo CETEM em parceria com a UFOP (Universidade Federal de Ouro Preto) e o Laborat&oacute;rio G&uuml;belin, da Su&iacute;&ccedil;a. O objetivo do pesquisador Jurgen foi a realiza&ccedil;&atilde;o de um trabalho de macrofotografia das pedras extra&iacute;das mais recentemente, tanto brutas quanto lapidadas, de modo a subsidiar a publica&ccedil;&atilde;o de um artigo em revista internacional indexada.</p>\r\n',52,'Pesquisador visita empresa para realizaÃÂ§ÃÂ£o de trabalho com esmeraldas',2,1,'null','2014-03-28 14:25:31'),(37,'<p style=\"text-align: justify;\">A equipe do N&uacute;cleo Regional do Esp&iacute;rito Santo (NR-ES), formada pela tecnologista Nuria Castro e pelo t&eacute;cnico Jefferson Carmago, realizar&aacute;, entre os dias de 28 de mar&ccedil;o e 04 de abril, um levantamento de consumo de hastes e brocas de perfura&ccedil;&atilde;o em pedreiras de granito em Ecoporanga, Esp&iacute;rito Santo e de quartzito em Gouveia, Minas Gerais. Esse tipo de trabalho &eacute; um dos servi&ccedil;os que s&atilde;o oferecidos pelo NR-ES.</p>\r\n',52,'NR-ES CETEM faz levantamento em pedreiras de granito e quartzito',2,1,'null','2014-03-28 14:26:15'),(38,'<p style=\"text-align:justify\"><img alt=\"\" src=\"/media/img/imagens/images/DSC08945.jpg\" style=\"float:left; height:256px; width:290px\" />O Dr. Carlos Magno, Engenheiro de Minas, da Universidade Federal de Pernambuco (UFPE) e coordenador do Projeto EA-UFPE &ndash; &ldquo;Caracteriza&ccedil;&atilde;o de Minerais Industriais &amp; Gemas do Nordeste e Estudo de Controle Ambiental das Atividades da Minera&ccedil;&atilde;o&rdquo; - ministra duas palestras sobre aspectos relativos ao projeto.</p>\r\n\r\n<p style=\"text-align:justify\">No dia 31 de mar&ccedil;o, nas depend&ecirc;ncias do CETEM, ministrou a palestra: <em>&quot;Projeto EA UFPE/CETEM: Monitoramento Ambiental das Opera&ccedil;&otilde;es de Lavra e Beneficiamento&quot;</em>. J&aacute; no dia 02 de abril, &agrave;s 10h, no audit&oacute;rio do IFES (Instituto Federal do Esp&iacute;rito Santo), Campus Cachoeiro de Itapemirim ser&aacute; a vez da palestra <em>&quot;Uso de instrumentos de Gest&atilde;o Ambiental nas Opera&ccedil;&otilde;es de Desmonte de Rochas e Beneficiamento&quot;.</em></p>\r\n\r\n<p style=\"text-align:justify\">Posteriormente o professor Carlos Magno, juntamente com os pesquisadores Francisco Hollanda e Leonardo Lyrio, realizar&atilde;o visitas t&eacute;cnicas as minas de calc&aacute;rios e rochas ornamentais da regi&atilde;o de Cachoeiro de Itapemirim. Logo ap&oacute;s, acontecer&aacute; um reuni&atilde;o espec&iacute;fica com os empres&aacute;rios dos setores para planejar como se dar&aacute; a execu&ccedil;&atilde;o dos trabalhos.&nbsp;</p>\r\n',52,'Projeto EA-UFPE: Coordenador ministra palestras para servidores do CETEM ',2,1,'null','2014-04-01 13:18:12'),(40,'<p style=\"text-align: justify;\">Nos dias 18 e 19 de mar&ccedil;o, foi ministrado nas depend&ecirc;ncias do CETEM o curso sobre o Software de Avalia&ccedil;&atilde;o de Ciclo de Vida - ACV SimaPro 8.2 e seu banco de dados nos n&iacute;veis b&aacute;sico e avan&ccedil;ado, com dura&ccedil;&atilde;o de 12h.&nbsp; O Software foi adquirido recentemente pelo CETEM para elabora&ccedil;&atilde;o do projeto em andamento <em>Avalia&ccedil;&atilde;o do Ciclo de Vida - ACV: o estudo de caso da demoli&ccedil;&atilde;o do ex-Bingo Arpoador</em>, assim como para pesquisa de bens minerais e agregados naturais e reciclados usados na ind&uacute;stria da constru&ccedil;&atilde;o civil.</p>\r\n\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">Participaram do curso os seguintes servidores do CETEM: Carlos Peiter, Nuria Castro, Jefferson Carmago, Pedro Palhano de Oliveira, Danielle Lima da Silva, Luciana Marelli Mofati, Francisco Mariano, Rosana Elisa Copped&ecirc; da Silva, Carlos Eduardo Ribeiro Wandermuren, Giancarlo Alfonso Lovon Canchumani.&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">O curso foi dado em tr&ecirc;s m&oacute;dulos. No primeiro foi passado aos alunos a parte introdut&oacute;ria da ferramenta e a descri&ccedil;&atilde;o inicial do SimaPro. Na segundo foram executados exerc&iacute;cios aplicados, modelagem de sistemas de produto, metodologias de avalia&ccedil;&atilde;o de impacto e interpreta&ccedil;&atilde;o.&nbsp; E no m&oacute;dulo final foi ministrada an&aacute;lise de incerteza e gest&atilde;o de dados.</p>\r\n',52,'Servidores passam por treinamento com software de ACV',2,1,'null','2014-04-02 15:49:56'),(41,'<p><span style=\"color:rgb(0, 0, 0); font-family:segoe ui_,open sans,verdana,arial,helvetica,sans-serif; font-size:15px\">A equipe de divulga&ccedil;&atilde;o institucional informa que, no m&ecirc;s de mar&ccedil;o&nbsp;</span><span style=\"color:rgb(0, 0, 0); font-family:segoe ui_,open sans,verdana,arial,helvetica,sans-serif; font-size:15px\">de 2014, foram publicadas na m&iacute;dia as seguintes not&iacute;cias:</span></p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/20140325%20-%20paracatu%20-%20ibram.pdf\" style=\"color: rgb(0, 136, 204); text-decoration: none;\" target=\"_blank\">Estudo aponta baixo risco &agrave; sa&uacute;de associado &agrave; ocorr&ecirc;ncia de ars&ecirc;nio</a><br />\r\nSite do IBRAM - 25/03/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/20140320%20-%20paracatu%20-%20site%20da%20kinross.pdf\" style=\"color: rgb(0, 136, 204); text-decoration: none;\" target=\"_blank\">Estudo aponta baixo risco &agrave; sa&uacute;de associado &agrave; ocorr&ecirc;ncia de ars&ecirc;nio</a><br />\r\nSite da Kinross - 20/03/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/20140319%20-%20labiotec%20-%20jornalciencia.pdf\" style=\"color: rgb(0, 136, 204); text-decoration: none;\" target=\"_blank\">CETEM promove semin&aacute;rio de biotecnologia e inaugura novo laborat&oacute;rio</a><br />\r\nJornal da Ci&ecirc;ncia e-mail n&ordm; 4915 - 19/04/2014&nbsp;</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/20140318%20-%20paracatu%20-%20paracatu.net.pdf\" style=\"color: rgb(0, 136, 204); text-decoration: none;\" target=\"_blank\">Relat&oacute;rio confirma que n&atilde;o h&aacute; contamina&ccedil;&atilde;o por ars&ecirc;nio em Paracatu</a><br />\r\nParacatu.net - 18/03/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/20140318%20-%20labiotec%20-%20portal%20brasil.pdf\" style=\"color: rgb(0, 136, 204); text-decoration: none; line-height: 1.6em;\" target=\"_blank\">CETEM promove semin&aacute;rio e inaugura novo laborat&oacute;rio</a><br />\r\nPortal Brasil - 18/03/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/20140318%20-%20labiotec%20-%20minerios%20e%20minerales.pdf\" style=\"color: rgb(0, 136, 204); text-decoration: none;\" target=\"_blank\">Petrobras e CETEM inauguram laborat&oacute;rio para biorremedia&ccedil;&atilde;o de &aacute;reas contaminadas</a><br />\r\nSite da revista Revista Min&eacute;rios &amp; Minerales - 18/03/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/20140318%20-%20labiotec%20-%20jornal%20brasil.pdf\" style=\"color: rgb(0, 136, 204); text-decoration: none;\" target=\"_blank\">CETEM promove semin&aacute;rio de biotecnologia e inaugura novo laborat&oacute;rio</a><br />\r\nJornal Brasil Online - 18/03/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/20140318%20-%20labiotec%20-%20portal%20mcti.pdf\" style=\"color: rgb(0, 136, 204); text-decoration: none;\" target=\"_blank\">CETEM promove semin&aacute;rio de biotecnologia e inaugura novo laborat&oacute;rio</a><br />\r\nPortal do MCTI - 18/03/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/20140317%20-%20lab%20uespi%20-%20portal%20gov%20piaui.pdf\" style=\"color: rgb(0, 136, 204); text-decoration: none;\" target=\"_blank\">Potencial em minera&ccedil;&atilde;o desperta interesse de pesquisadores do Piau&iacute;</a><br />\r\nPortal do Governo do Estado do Piau&iacute; - 17/03/2014</p>\r\n\r\n<p><a href=\"http://www.cetem.gov.br/files/docs/20140312%20-%20lab%20uespi%20-%20portal%20uespi.pdf\" style=\"color: rgb(0, 136, 204); text-decoration: none;\" target=\"_blank\">Diretores do CETEM-RJ e administra&ccedil;&atilde;o da UESPI discutem parcerias para pesquisas</a><br />\r\nSite da Universidade Estadual do Piau&iacute; - 12/03/2014</p>\r\n\r\n<p><span style=\"color:rgb(0, 0, 0); font-family:segoe ui_,open sans,verdana,arial,helvetica,sans-serif; font-size:15px\">As mat&eacute;rias acima listadas est&atilde;o dispon&iacute;veis externamente em nosso site:&nbsp;</span><a href=\"http://www.cetem.gov.br/comunicacao/clipping\" style=\"box-sizing: border-box; border-collapse: collapse; color: rgb(46, 146, 207); font-family: \'Segoe UI_\', \'Open Sans\', Verdana, Arial, Helvetica, sans-serif; font-size: 15px; letter-spacing: 0.29333335161209106px; line-height: 20px; text-decoration: none !important;\">http://www.cetem.gov.br/comunicacao/clipping&nbsp;</a><span style=\"color:rgb(0, 0, 0); font-family:segoe ui_,open sans,verdana,arial,helvetica,sans-serif; font-size:15px\">&nbsp;</span></p>\r\n',51,'CETEM na mÃÂ­dia: balanÃÂ§o marÃÂ§o',2,1,'null','2014-04-02 16:16:16'),(44,'<p style=\"text-align:justify\">O CETEM, por meio do Tecnologista S&ecirc;nior Carlos Peiter, apresentou, no dia 28 de mar&ccedil;o, ao DRM-RJ (Servi&ccedil;o Geol&oacute;gico do Estado do Rio de Janeiro), apresentou uma proposta de parceria para retomada de trabalhos sobre sustentabilidade da pequena minera&ccedil;&atilde;o e seus arranjos produtivos (APLs). A proposta metodol&oacute;gica &eacute; adaptar os indicadores do &ldquo;&Iacute;ndice de Sustentabilidade de Minas&rdquo;, proposto por Mauricio Viana e Saulo Rodrigues, da UnB, para a realidade de pequenas minas ou pedreiras e ainda avaliar os indicadores para a situa&ccedil;&atilde;o de aglomerados de pequenas minas, como os APLs de rochas ornamentais de Santo Ant&ocirc;nio de P&aacute;dua e/ou de cer&acirc;mica de Campos dos Goytacazes. Na reuni&atilde;o ficou proposto que CETEM e DRM-RJ buscar&atilde;o recursos institucionais e nos editais em vigor para realizar a pesquisa.</p>\r\n\r\n<p style=\"text-align:justify\">A parceria entre CETEM e DRM-RJ come&ccedil;ou com sucesso entre 1998 e 2002 na forma&ccedil;&atilde;o da rede cooperativa de pesquisa RETECMIN-RJ (Rede Cooperativa de Pesquisa em Minerais da Constru&ccedil;&atilde;o Civil e Mitiga&ccedil;&atilde;o de seus Impactos Ambientais), que contou com apoio da FAPERJ, tendo ainda como parceiros o INT, e o Departamento de Geologia da UFRJ. A Rede elaborou e executou estudos e projetos que promoveram mudan&ccedil;as positivas na atividade mineral do noroeste fluminense viabilizando o TAC (Termo de Ajuste de Conduta) para as pedreiras de P&aacute;dua, al&eacute;m de colaborar na obten&ccedil;&atilde;o de licen&ccedil;as de funcionamento das pequenas serrarias e do reaproveitamento do rejeito finamente particulado na f&aacute;brica de argamassa idealizada pelo CETEM e INT, que foi constru&iacute;da e operada pela empresa Argamil em P&aacute;dua.</p>\r\n\r\n<h3 style=\"text-align:justify\">&nbsp;</h3>\r\n',52,'CETEM e DRM-RJ fecham nova parceria',2,1,'null','2014-04-09 15:07:39'),(45,'<p style=\"text-align: justify;\">A Profa. Adriana de Aquino Soeiro, do IFRJ (Instituto Federal de Educa&ccedil;&atilde;o, Ci&ecirc;ncia e Tecnologia do Rio de Janeiro), teve a sua tese de doutorado, cujo t&iacute;tulo foi: <em>&ldquo;S&iacute;ntese e Caracteriza&ccedil;&atilde;o Estrutural de Materiais com Libera&ccedil;&atilde;o Controlada de Pot&aacute;ssio&rdquo;</em>, aprovada pelo IQ/UFRJ (nota 7 pela CAPES). Adriana contou com a colabora&ccedil;&atilde;o do pesquisador Jo&atilde;o Alves Sampaio do CETEM como coorientador. Os trabalhos experimentais relativos &agrave; tese foram desenvolvidos nos laborat&oacute;rios do CETEM.</p>\r\n\r\n<p style=\"text-align: justify;\">Os seus orientadores pelo IQ-UFRJ foram a Profa. Marta Medeiros e o Prof. Francisco Garrido, que, juntamente com a Profa. Adriana Soeiro, desenvolveram um excelente trabalho de pesquisa na &aacute;rea dos Agrominerais, uma das linhas estruturantes do CETEM.</p>\r\n',52,'Tese de doutorado desenvolvida no CETEM ÃÂ© aprovada',2,1,'null','2014-04-10 15:19:30'),(46,'<p style=\"text-align: justify;\">O CETEM ir&aacute; participar da 37&ordf; Reuni&atilde;o Anual da SBQ (Sociedade Brasileira de Qu&iacute;mica), que reuni estudantes, p&oacute;s-graduandos, pesquisadores, t&eacute;cnicos e profissionais da ind&uacute;stria, com a apresenta&ccedil;&atilde;o de dois trabalhos, entre os dias 26 e 29 de maio, em Natal, Rio Grande do Norte.</p>\r\n\r\n<p style=\"text-align: justify;\">Isabella Ces&aacute;rio de Amaral, bolsita PCI, ir&aacute; apresentar o estudo: <em>&ldquo;Avalia&ccedil;&atilde;o da cin&eacute;tica de libera&ccedil;&atilde;o do K+ em fun&ccedil;&atilde;o dos diferentes tamanhos de part&iacute;cula da rocha flogopitito&rdquo;</em>.</p>\r\n\r\n<p style=\"text-align: justify;\">Enquanto, Danielle da Silva Rosa, bolsista PCI, ir&aacute; apresentar o estudo:&nbsp;<em>&ldquo;</em><em>Estudo da Intera&ccedil;&atilde;o de resinas com a Albita por</em> <em>Din&acirc;mica Molecular&rdquo;. </em></p>\r\n',52,'Bolsistas do CETEM apresentam trabalho na 37ÃÂº SBQ',2,1,'null','2014-04-10 15:20:12'),(48,'<p><img alt=\"\" src=\"/media/img/imagens/images/_DSC0002.JPG\" style=\"float:left; height:181px; width:270px\" />Nos dias 18 a 20 de mar&ccedil;o, a pesquisadora Silvia Fran&ccedil;a, da COPM, ministrou treinamento sobre &quot;Filtragem - Conceitos e aspectos operacionais&quot; a uma turma de engenheiros e t&eacute;cnicos de processo da empresa Alunorte (Alumina do Norte do Brasil SA) l&iacute;der mundial na produ&ccedil;&atilde;o de alumina &ndash; produ&ccedil;&atilde;o de cerca de 6,8 milh&otilde;es de toneladas por ano -, no munic&iacute;pio de Barcarena, Par&aacute;.</p>\r\n\r\n<p>O objetivo do treinamento foi abordar aspectos te&oacute;ricos e operacionais da filtragem na cadeia do alum&iacute;nio e prover aos especialistas/operadores da &aacute;rea industrial conhecimento que facilite o diagn&oacute;stico e a solu&ccedil;&atilde;o de problemas operacionais, bem como implementar melhorias no processo, acarretando assim impactos positivos ao processo de filtragem e em todo o circuito da refinaria, como um todo.</p>\r\n',52,'Pesquisadora ministra curso em empresa lÃÂ­der mundial na produÃÂ§ÃÂ£o de alumina',2,1,'null','2014-04-10 15:26:46'),(49,'<p style=\"text-align: justify;\">A bolsita Camila Arruda teve sua monografia, cujo tema foi a &ldquo;A avalia&ccedil;&atilde;o da aplica&ccedil;&atilde;o de res&iacute;duos do m&aacute;rmore Bege Bahia na matriz do polipropileno&rdquo; aprovada, conclu&iacute;do assim o curso de Engenharia de Materiais e Metal&uacute;rgica, da UFRJ. Foram avaliados durante o trabalho: teores m&aacute;ximos da aplica&ccedil;&atilde;o de res&iacute;duo, ensaios mec&acirc;nicos, pr&eacute;-viabilidade econ&ocirc;mica e gera&ccedil;&atilde;o de mobili&aacute;rio escolar. Camila foi orientada pelo pesquisador do CETEM Roberto Carlos Ribeiro e pelo professor Luiz Bastian da UFRJ.</p>\r\n',52,'Bolsista tem monografia aprovada',2,1,'null','2014-04-14 11:47:01'),(50,'<p style=\"text-align: justify;\">O Dr. Francisco Hollanda, coordenador da CATE e do projeto APL Opala do Piau&iacute;, realizou, juntamente com o Prof. Dr. Jos&eacute; Nogueira, uma visita t&eacute;cnica em campo na regi&atilde;o de Pedro II e Buriti dos Montes, no estado do Piau&iacute;, com o objetivo de realizar um diagn&oacute;stico voltado &agrave; geologia de explora&ccedil;&atilde;o dos dep&oacute;sitos de opala e quartzo, no per&iacute;odo de 14 a 16 de abril.</p>\r\n\r\n<p style=\"text-align: justify;\">Na oportunidade, tamb&eacute;m participou da visita o bolsita ge&oacute;logo Agnaldo Francisco de Freitas Filho, que foi contratado recentemente para executar o mapeamento geol&oacute;gico de detalhe das &aacute;reas em explora&ccedil;&atilde;o de opalas priorit&aacute;rias na regi&atilde;o de Pedro II.</p>\r\n',52,'APL OPALA: Coordenador do CETEM participa de diagnÃÂ³stico voltado ÃÂ  geologia local',2,1,'null','2014-04-16 14:52:35'),(51,'<p style=\"text-align: justify;\">A t&eacute;cnica Patricia Araujo participou de reuni&atilde;o com o CODEMA - Conselho Municipal de Desenvolvimento Ambiental de Ouro Preto, juntamente com a Empresa MICAPEL - Minera&ccedil;&atilde;o Cap&atilde;o das Pedras Ltda. e artes&atilde;os de Mata dos Palmitos, no dia 11 de abril.</p>\r\n\r\n<p style=\"text-align: justify;\">O objetivo do encontro foi discutir a rela&ccedil;&atilde;o entre a empresa e os artes&atilde;os de Mata dos Palmitos, Ouro Preto.A presen&ccedil;a do CETEM na reuni&atilde;o foi devido aos trabalhos previamente desenvolvidos pelo Centro na regi&atilde;o. A continuidade desses trabalhos depende de um novo Termo de Compromisso a ser firmado entre o CETEM e a Prefeitura de Ouro Preto.</p>\r\n',52,'CETEM discute continuidade de projetos com o Conselho Municipal de Desenvolvimento Ambiental de Ouro Preto',2,1,'null','2014-04-24 13:59:24'),(52,'<p style=\"text-align: justify;\">Foram apresentados, nas depend&ecirc;ncias do CETEM, nos dias 25 e 28 de abril, os pleitos de progress&atilde;o dos servidores, de n&iacute;vel superior, das carreiras de Pesquisa em C&amp;T e de Desenvolvimento Tecnol&oacute;gico.</p>\r\n\r\n<p style=\"text-align: justify;\">As apresenta&ccedil;&otilde;es foram feitas na Sala 7 do pavilh&atilde;o did&aacute;tico do CETEM. No dia 25, os servidores da CATE defenderam seu pleito. Enquanto no dia 28, foi a vez dos servidores da CPMA e da COAM executarem suas defesas.</p>\r\n\r\n<p style=\"text-align: justify;\">As defesas dos pleitos estiveram abertas aos servidores do CETEM, de acordo&nbsp; com o par&aacute;grafo 1&ordm;, do artigo 4&ordm; -&nbsp; portaria 019 de 08/04/13.</p>\r\n',52,'Servidores apresentam pleitos de progressÃÂ£o funcional',2,1,'null','2014-05-05 15:45:41'),(53,'<p style=\"text-align: justify;\">Os servidores Renata Queiroz Affonso e Bruno Montandon Noronha Barros, do NIT do CETEM, participaram, no per&iacute;odo de 11 a 17 de abril, do evento sobre inova&ccedil;&atilde;o, transfer&ecirc;ncia de tecnologia e economia criativa promovido pelo IBICT (Instituto Brasileiro de Informa&ccedil;&atilde;o em Ci&ecirc;ncia e Tecnologia), no Rio de Janeiro.</p>\r\n\r\n<p style=\"text-align: justify;\">O evento consistiu em uma palestra sobre <em>&ldquo;Superfusion&rdquo;:</em> como as empresas de tecnologia criativa/digital/da informa&ccedil;&atilde;o est&atilde;o impulsionando o desenvolvimento socioecon&ocirc;mico. A palestra baseia-se em um estudo feito no Reino unido que indica que as empresas que combinam habilidades em design criativo e tecnologia digital crescem quase tr&ecirc;s vezes mais r&aacute;pido do que aquelas que operam em uma &uacute;nica &aacute;rea.&nbsp; A &ldquo;superfus&atilde;o&rdquo; combina componentes como Artes, Ci&ecirc;ncias Humanas, C&amp;T, Marketing, Engenharia e Matem&aacute;tica.</p>\r\n\r\n<p style=\"text-align: justify;\">Durante o evento, os dois integrantes do NIT/CETEM, Renata e&nbsp; Bruno,&nbsp; tamb&eacute;m participaram do curso <em>&ldquo;Inova&ccedil;&atilde;o e Transfer&ecirc;ncia de Tecnologia&rdquo;</em> que buscou analisar, entre outros,&nbsp; os seguintes temas: fontes de inova&ccedil;&atilde;o, compartilhamento de conhecimento,&nbsp; comercializa&ccedil;&atilde;o e apropria&ccedil;&atilde;o de tecnologia.</p>\r\n\r\n<p style=\"text-align: justify;\">O curso e a palestra foram ministrados pelo Doutor e Mestre no Science and Technology Policy Studies (SPRU), Universidade de Sussex, Dr. Jonathan Sapsed, que atualmente atua como professor e pesquisador na &aacute;rea de gest&atilde;o e pol&iacute;tica de inova&ccedil;&atilde;o no Centro de Pesquisa em Gest&atilde;o da Inova&ccedil;&atilde;o (CENTRIM).</p>\r\n',52,'InovaÃÂ§ÃÂ£o e economia criativa: Integrantes do NIT participam de curso e palestra promovidos pelo IBICT',2,1,'null','2014-05-05 15:47:27'),(54,'<p style=\"text-align: justify;\">As servidoras Vera L&uacute;cia Souza e Thatyana Freitas, que integram a equipe de Divulga&ccedil;&atilde;o Institucional da CPGI, est&atilde;o participando do <em>PSCT 2014 &ndash; 13th International Public Communication of Science and Technology Conference</em>, entre os dias 05 a 08 de maio, em Salvador. O tema central da confer&ecirc;ncia, que j&aacute; t&ecirc;m contabilizadas mais de 450 inscri&ccedil;&otilde;es, &eacute; a import&acirc;ncia da d<em>ivulga&ccedil;&atilde;o da Ci&ecirc;ncia para a inclus&atilde;o social e o engajamento pol&iacute;tico</em><em>. </em></p>\r\n\r\n<p style=\"text-align: justify;\">O MCTI foi representado na abertura do evento pelo diretor do Departamento de Populariza&ccedil;&atilde;o e Difus&atilde;o de Ci&ecirc;ncia e Tecnologia da Secretaria de Ci&ecirc;ncia e Tecnologia para a Inclus&atilde;o Social (Secis), Douglas Falc&atilde;o. Em seu discurso, ele falou sobre a cria&ccedil;&atilde;o do departamento, em 2004, as parcerias realizadas e os resultados alcan&ccedil;ados. Segundo o diretor, ao longo dos &uacute;ltimos 10 anos, 6000 projetos foram submetidos e 1800 deles aprovados em editais de populariza&ccedil;&atilde;o da ci&ecirc;ncia. Para Falc&atilde;o, a pesquisa cient&iacute;fica deve caminhar junto com a pr&aacute;tica de populariza&ccedil;&atilde;o da ci&ecirc;ncia.</p>\r\n\r\n<p style=\"text-align: justify;\"><em>Esta &eacute; a primeira vez que o evento &eacute; realizado em um pa&iacute;s da Am&eacute;rica Latina, em 20 anos. </em>A&nbsp;Rede Internacional de Comunica&ccedil;&atilde;o P&uacute;blica da Ci&ecirc;ncia e da Tecnologia&nbsp;(PCST, em sua sigla em ingl&ecirc;s) &eacute; uma rede de indiv&iacute;duos de diversas partes do mundo, incluindo jornalistas e divulgadores cient&iacute;ficos, que produzem e estudam na &aacute;rea de comunica&ccedil;&atilde;o p&uacute;blica da C&amp;T e tem como principal objetivo estimular a comunica&ccedil;&atilde;o p&uacute;blica da ci&ecirc;ncia e tecnologia.</p>\r\n\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">Reda&ccedil;&atilde;o: Thatyana Freitas</p>\r\n',52,'Servidoras participam de conferÃÂªncia sobre divulgaÃÂ§ÃÂ£o cientÃÂ­fica em Salvador, cujo tema central ÃÂ© a importÃÂ¢ncia desta atividade para a inclusÃÂ£o social e o engajamento polÃÂ­tico ',2,1,'null','2014-05-07 15:42:55'),(55,'<p style=\"text-align: justify;\">O t&eacute;cnico Elton dos Santos esteve no Rio de Janeiro, no dia 12 de maio, representando o NR-ES (N&uacute;cleo Regional do CETEM Esp&iacute;rito Santo) em reuni&atilde;o da Comiss&atilde;o Permanente de Insalubridade e Periculosidade do CETEM. A comiss&atilde;o d&aacute; sequ&ecirc;ncia a sua miss&atilde;o de acompanhar permanentemente as condi&ccedil;&otilde;es de insalubridade e periculosidade nas unidades f&iacute;sicas que comp&otilde;em o Centro.</p>\r\n',52,'Representante do NR-ES participa de reuniÃÂ£o da ComissÃÂ£o Permanente de Insalubridade e Periculosidade do CETEM',2,1,'null','2014-05-15 15:37:35'),(56,'<p style=\"text-align: justify;\">O servidor Flavio Balduino de Brito, integrante do Comit&ecirc; Interno de Melhoria de Gest&atilde;o do CETEM, participou, no per&iacute;odo de 06 a 07 de abril, da 8&ordf; Edi&ccedil;&atilde;o do Congresso da ABIPTI (Associa&ccedil;&atilde;o Brasileira das Institui&ccedil;&otilde;es de Pesquisa Tecnol&oacute;gica e Inova&ccedil;&atilde;o), evento patrocinado pelo MCTI, promovido com intuito de reunir os principais representantes do setor de CT&amp;I para debater e trocar experi&ecirc;ncias exitosas que possam vir a contribuir com o desenvolvimento das entidades de pesquisa, desenvolvimento e inova&ccedil;&atilde;o (EPDIs).</p>\r\n\r\n<p style=\"text-align: justify;\">O evento, que foi realizado em Bras&iacute;lia, tratou de temas como a intera&ccedil;&atilde;o entre as Institui&ccedil;&otilde;es Cient&iacute;ficas e Tecnol&oacute;gicas (ICTs) e o setor empresarial na promo&ccedil;&atilde;o da inova&ccedil;&atilde;o no Brasil em seus mais variados seguimentos. Durante o evento foram expostos os trabalhos vencedores do concurso que visou premiar as experi&ecirc;ncias exitosas promovidas pelas EPDIs.</p>\r\n\r\n<p style=\"text-align: justify;\">Flavio destaca as palavras da Presidente da ABIPTI, Isa Assef dos Santos: <em>&ldquo;Sem excel&ecirc;ncia na gest&atilde;o, n&atilde;o pode haver efetividade no uso dos recursos de qualquer natureza.&rdquo;</em> ressaltando a import&acirc;ncia do trabalho de Melhoria Cont&iacute;nua de Gest&atilde;o do CETEM diante das novas demandas de desenvolvimento tecnol&oacute;gico das EPDI&acute;s que ampliam o foco da produ&ccedil;&atilde;o cient&iacute;fica em atendimento as necessidades do setor produtivo do pa&iacute;s.</p>\r\n',52,'Congresso ABIPTI 2014: Representante do CETEM participa das palestras e dos debates que tiveram como tema Ã¢â¬ÅO ambiente inovador no Brasil: Desafios para o Desenvolvimento SocioeconÃÂ´micoÃ¢â¬Â',2,1,'null','2014-05-15 15:38:30'),(61,'<p style=\"text-align: justify;\">O CETEM doou &agrave; Cooperativa Coopquitungo, no &uacute;ltimo dia 08 de maio, os seguintes materiais recicl&aacute;veis: 243,5 quilos de papel&atilde;o,&nbsp; 138,5 quilos de papel em geral, 11 quilos de pl&aacute;stico, 33 quilos de latinhas de alum&iacute;nio e 20 quilos de outros materiais met&aacute;licos. A doa&ccedil;&atilde;o segue as diretrizes propostas no Termo de Compromisso para recolhimento de res&iacute;duos recicl&aacute;veis firmado entre o Centro &ndash; por meio da Comiss&atilde;o de Coleta Seletiva Solid&aacute;ria (CCSS) &ndash; e a cooperativa, em fevereiro deste ano. Essa foi a terceira retirada de materiais em 2014, e a CCSS contou com a colabora&ccedil;&atilde;o do servidor Luciano Borges (CPMA).</p>\r\n',52,'Coleta seletiva solidÃÂ¡ria: balanÃÂ§o da terceira retirada de materiais reciclÃÂ¡veis ',2,1,'null','2014-05-19 10:58:38'),(62,'<p>O coordenador da CATE, Dr. Francisco Hollanda, estar&aacute; em Recife, no per&iacute;odo de 20 a 25 de maio, para participar de reuni&otilde;es e visitas t&eacute;cnicas no &acirc;mbito do projeto das Entidades Associadas da UFPE (Universidade Federal de Pernambuco) e UFCG (Universidade Federal de Campina Grande).</p>\r\n\r\n<p>Ambos os projetos foram iniciados em setembro de 2013, com previs&atilde;o de dois anos para serem executados. No momento, ser&atilde;o elaborados relat&oacute;rios parciais para que seja liberada a segunda, e &uacute;ltima, parcela de execu&ccedil;&atilde;o do projeto por parte do MCTI.</p>\r\n',52,'Projetos EAs: Coordenador do CETEM vai ao Recife para elaboraÃÂ§ÃÂ£o de relatÃÂ³rios parciais',2,1,'null','2014-05-20 15:55:19'),(63,'<p style=\"text-align: justify;\">A estagi&aacute;ria do CETEM Leticia Maia Prates ir&aacute; participar, entre os dias 27 e 29 de maio, do minicurso &ldquo;<em>A adsor&ccedil;&atilde;o em superf&iacute;cies e as aplica&ccedil;&otilde;es em cat&aacute;lise&rdquo;</em>, que ser&aacute; ministrado pela Dra.&nbsp;Michele Oberson de Souza, da UFRGS <em>(<em>Universidade Federal do Rio Grande do Sul), durante a </em></em>37&ordf; Reuni&atilde;o Anual da SBQ (Sociedade Brasileira de Qu&iacute;mica).</p>\r\n\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">No minicurso ser&atilde;o abordados os princ&iacute;pios que permitem caracterizar a superf&iacute;cie de s&oacute;lidos envolvidos em processos catal&iacute;ticos empregando m&eacute;todos de adsor&ccedil;&atilde;o de gases. A SBQ &eacute; o maior evento em qu&iacute;mica da Am&eacute;rica Latina, e reuni cerca de cerca de 2500 pesquisadores, professores e estudantes.&nbsp;</p>\r\n',52,'EstagiÃÂ¡ria participa de minicurso sobre processos catalÃÂ­ticos e mÃÂ©todos de adsorÃÂ§ÃÂ£o de gases durante a 37ÃÂª SBQ',2,1,'null','2014-05-20 15:58:17'),(64,'<blockquote dir=\"ltr\">\r\n<p><strong>FLAVIO</strong>: Grupos 1, 2 e 3 e o levantamento dos indicadores da&nbsp;CPGI + Introdu&ccedil;&atilde;o do Relat&oacute;rio</p>\r\n\r\n<p><strong>J&Uuml;RGEN</strong>: Grupo 4&nbsp;+ Levantamento dos indicadores da GRACE</p>\r\n\r\n<p><strong><strong>&Aacute;UREO</strong>&nbsp;e MANUEL</strong>: 5&nbsp;+ Levantamento dos indicadores do&nbsp;SEIN e Biblioteca</p>\r\n\r\n<p><strong>SILVIA e ROBSON</strong>: 6&nbsp;+ levantamento dos indicadores da COAD</p>\r\n\r\n<p><strong>ANDR&Eacute;IA</strong>: Grupo 7 +Introdu&ccedil;&atilde;o do Relat&oacute;rio</p>\r\n</blockquote>\r\n',55,'Apoio Individual ao Preenchimento do RelatÃÂ³rio de 26 a 30 de Maio',1,1,'null','2014-05-23 09:07:30'),(65,'<blockquote dir=\"ltr\">\r\n<p>Dia 02/06 - Segunda:&nbsp;(09:00) - Grupo 7 <span style=\"background-color:#FFD700\">CONCLUIDO </span>/&nbsp;(13:00) - Grupo 1 <span style=\"background-color:#FFD700\">CONCLUIDO</span></p>\r\n\r\n<p>Dia 03/06 - Ter&ccedil;a : (09:30) - Grupo 2 / (13:30) - Grupo 3</p>\r\n\r\n<p>Dia 04/06 - Quarta: (09:30) - Grupo 4 / (13:30 - Grupo 5</p>\r\n\r\n<p>Dia 05/06 - Quinta: (09:30) - Grupo 6 / (13:30) - Grupo 7</p>\r\n\r\n<p>Dia 06/06 - Sexta: (09:30) - Grupo 8 - <strong>Entrega &agrave; Dire&ccedil;&atilde;o</strong></p>\r\n</blockquote>\r\n',55,'Agenda de ReuniÃÂµes de Fechamento de 02 a 06 de Junho',2,1,'null','2014-05-23 09:08:53'),(66,'<blockquote dir=\"ltr\">\r\n<p>-&gt;Avalia&ccedil;&atilde;o dos Coordenadores de<strong> 09 a 13/06/2014</strong></p>\r\n\r\n<p>-&gt;Entrega do Relat&oacute;rio de&nbsp;Auto-avalia&ccedil;&atilde;o&nbsp;dia<strong> 16/06/2014</strong></p>\r\n</blockquote>\r\n',55,'Etapas finais - AvaliaÃÂ§ÃÂ£o da DireÃÂ§ÃÂ£o e Entrega ao Gespublica',2,1,'null','2014-05-23 09:12:24'),(67,'<p style=\"text-align: justify;\">A bolsista Rosana Coppede ir&aacute; a Ouro Preto, Minas Gerais, no per&iacute;odo de 02 a 13 de junho, selecionar pedreiras de pedra sab&atilde;o para futuras atividades de restauro. Essa viagem faz parte do trabalho de caracteriza&ccedil;&atilde;o e estudo de alterabilidade das pedras sab&atilde;o que o CETEM vem desenvolvendo para subsidiar as atividades de restauro e conserva&ccedil;&atilde;o de monumentos hist&oacute;ricos do Rio de Janeiro.</p>\r\n\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">Durante a viagem, Rosana tamb&eacute;m ir&aacute; coletar amostras de pedra sab&atilde;o e quartzito para estudos de poss&iacute;veis utiliza&ccedil;&otilde;es dos res&iacute;duos desses materiais.</p>\r\n',52,'Bolsista do CETEM busca pedreiras de pedra sabÃÂ£o visando atividades de restauro',2,1,'null','2014-06-02 11:06:31'),(68,'<p style=\"text-align: justify;\">Os bolsistas Davi Vargas Souza e Douglas Bortolote Marcon, do NR-ES, sob a orienta&ccedil;&atilde;o do Dr. Francisco Hollanda, e em conjunto com os t&eacute;cnicos da COPM e da CATE, realizaram testes de rotas de processamento de diferentes res&iacute;duos de rochas ornamentais na usina piloto do CETEM.</p>\r\n\r\n<p style=\"text-align: justify;\">O objetivo desse trabalho &eacute; obter produtos de aplica&ccedil;&atilde;o industrial a partir dos res&iacute;duos provenientes das serragens de blocos de teares convencionais e multifio.</p>\r\n',52,'Bolsistas do NR-ES testam rota de processamento de resÃÂ­duos de rochas ornamentais',2,1,'null','2014-06-03 13:28:53'),(69,'<p style=\"text-align: justify;\">Recentemente foram publicados no site do CETEM os PDFs das seguintes S&eacute;ries Monogr&aacute;ficas:</p>\r\n\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\"><strong>STA-67&nbsp;- Log&iacute;stica Reversa: Instrumento da Gest&atilde;o Compartilhada na Atual Pol&iacute;tica Nacional de Res&iacute;duos S&oacute;lidos</strong><br />\r\nEraldo Jos&eacute; Brand&atilde;o e Luis Gonzaga Santos Sobral, 2012.<br />\r\n<a href=\"http://www.cetem.gov.br/publicacao/series_sta/sta-67.pdf\" target=\"_blank\">download (pdf - 376kb)</a></p>\r\n\r\n<p style=\"text-align: justify;\"><strong>STA-66&nbsp;- Solubiliza&ccedil;&atilde;o Biol&oacute;gica de Pot&aacute;ssio</strong><br />\r\nDiego Valentim Crescente Cara, Daniele Leonel da Rocha, Cl&aacute;udia Duarte da Cunha, Andr&eacute;a Camardella de Lima Rizzo e Eliana Fl&aacute;via Camporese S&eacute;rvulo, 2012.<br />\r\n<a href=\"http://www.cetem.gov.br/publicacao/series_sta/sta-66.pdf\" target=\"_blank\">download (pdf - 376kb)</a></p>\r\n\r\n<p style=\"text-align: justify;\"><strong>STA-65&nbsp;- M&eacute;todos para Tratamento Biol&oacute;gico de Drenagem &Aacute;cida de Mina &ndash; DAM</strong><br />\r\nCl&aacute;udia Afonso Barros, Julia Carestiato Rodrigues, Grace Maria de Britto, Cl&aacute;udia Duarte da Cunha, Andr&eacute;a Camardella de Lima Rizzo e Paulo S&eacute;rgio Moreira Soares, 2012.<br />\r\n<a href=\"http://www.cetem.gov.br/publicacao/series_sta/sta-65.pdf\" target=\"_blank\">download (pdf - 376kb)</a></p>\r\n\r\n<p style=\"text-align: justify;\"><strong>STA-64&nbsp;- Xisto Retortado e P&oacute; da Casca do Coco Verde como Sorventes Alternativos para Ars&ecirc;nio e &Oacute;leos e Graxas</strong><br />\r\nAdriana Loeser, Cl&aacute;udia Duarte da Cunha, Selma Gomes Ferreira Leite, Fernando Jorge Santos Oliveira, 2012.<br />\r\n<a href=\"http://www.cetem.gov.br/publicacao/series_sta/sta-64.pdf\" target=\"_blank\">download (pdf - 376kb)</a></p>\r\n\r\n<p style=\"text-align: justify;\"><strong>STA-63&nbsp;- Recovery of defective Discs in the production of New Real coins by intensive Cyanidation</strong></p>\r\n\r\n<p style=\"text-align: justify;\">Paula Franco Cabral do Nascimento, Luis Gonzaga Santos Sobral, Carlos Eduardo Gomes de Souza, Priscila Martins da Rocha, Diogo de Oliveira Padr&atilde;o, 2012.<br />\r\n<a href=\"http://www.cetem.gov.br/publicacao/series_sta/sta-63.pdf\" target=\"_blank\">download (pdf - 376kb)</a></p>\r\n\r\n<p style=\"text-align: justify;\"><strong>STA-62&nbsp;- Urban Mining: the way out for recycling non-renewable metal values</strong></p>\r\n\r\n<p style=\"text-align: justify;\">Luis Gonzaga Santos Sobral, Priscila Martins da Rocha, Diogo de Oliveira Padr&atilde;o, D&eacute;bora Monteiro de Oliveira, 2012.<br />\r\n<a href=\"http://www.cetem.gov.br/publicacao/series_sta/sta-62.pdf\" target=\"_blank\">download (pdf - 376kb)</a></p>\r\n',52,'PDF\'s de sÃÂ©ries monogrÃÂ¡ficas sÃÂ£o publicados no site do CETEM',2,1,'null','2014-06-03 13:32:44'),(70,'<p style=\"text-align: justify;\">A servidora do SERH (Servi&ccedil;o de Recursos Humanos) Nath&aacute;lia Nascimento solicitou vac&acirc;ncia do CETEM, a partir do &uacute;ltimo dia 02 de Junho, para assumir o cargo de Analista no IBGE (Instituto Brasileiro de Geografia e Estat&iacute;stica). J&aacute; o servidor Antonio Carlos Feitosa Costa, removido para o CETEM do LNCC (Laborat&oacute;rio Nacional de Computa&ccedil;&atilde;o Cient&iacute;fica), passou a exercer a fun&ccedil;&atilde;o de t&eacute;cnico no SEIN (Servi&ccedil;o de Informa&ccedil;&atilde;o) a partir do dia 02 de Junho.</p>\r\n',52,'MovimentaÃÂ§ÃÂ£o de servidores: VacÃÂ¢ncia no SERH e remoÃÂ§ÃÂ£o do LNCC para o SEIN',2,1,'null','2014-06-04 11:13:23'),(71,'<p style=\"text-align: justify;\">O CETEM recebeu, no &uacute;ltimo dia 03 de junho, a visita do Prof. Dr. Geraldo Eduardo da Luz J&uacute;nior, Pr&oacute;-Reitor de Administra&ccedil;&atilde;o e Recursos Humanos da Universidade Estadual do Piau&iacute; (UESPI), que falou sobre as linhas de pesquisa da UESPI e sobre os resultados provenientes de parceria t&eacute;cnico-cient&iacute;fica entre o CETEM e a universidade. Dentre os resultados, destaca-se a inaugura&ccedil;&atilde;o de um laborat&oacute;rio de tecnologia no campus Torquato Neto e o desenvolvimento de estudos sobre importantes temas para a regi&atilde;o: &aacute;guas subterr&acirc;neas do estado do Piau&iacute;, atapulgita de Guadalupe e aproveitamento de res&iacute;duos da pedra mourisca da regi&atilde;o de Castelo.&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">Tamb&eacute;m estiveram presentes no encontro o Reitor da UESPI, Prof. Dr. Nouga Cardoso Batista, e o Superintendente de Ci&ecirc;ncia e Tecnologia da Secret&aacute;ria de Desenvolvimento Econ&ocirc;mico e Tecnol&oacute;gico do Estado do Piau&iacute;, Prof. Dr. Francisco Soares Santos Filho.&nbsp;&nbsp;</p>\r\n',52,'CETEM recebe professores da UNIVERSIDADE ESTADUAL do PiauÃÂ­ pra discutir antigas e novas parcerias ',2,1,'null','2014-06-05 16:38:27'),(72,'<p style=\"text-align: justify;\">A pesquisadora Zuleica C. Castilhos esteve na para cidade de Paracatu, em Minas Gerais, no dia 20 de maio, para apresentar para popula&ccedil;&atilde;o os resultados dos exames de ars&ecirc;nio em urina, sangue e cabelo feitos por cada participante do estudo intitulado: <em>&quot;Avalia&ccedil;&atilde;o da contamina&ccedil;&atilde;o ambiental por ars&ecirc;nio e estudo epidemiol&oacute;gico da exposi&ccedil;&atilde;o ambiental da popula&ccedil;&atilde;o humana de Paracatu &ndash; MG&rdquo;</em>, que foi coordenado pela pesquisadora, cujo objetivo foi realizar uma avalia&ccedil;&atilde;o da contamina&ccedil;&atilde;o ambiental por ars&ecirc;nio e um estudo epidemiol&oacute;gico da exposi&ccedil;&atilde;o ambiental associada em popula&ccedil;&otilde;es humanas da cidade.&nbsp;</p>\r\n\r\n<p style=\"text-align: justify;\">Com isso o CETEM visa assegurar que a popula&ccedil;&atilde;o venha a ter condi&ccedil;&otilde;es de se apropriar do conhecimento t&eacute;cnico, estimulando a constru&ccedil;&atilde;o individual e coletiva da cidadania, da educa&ccedil;&atilde;o em sa&uacute;de e do controle social.&nbsp;</p>\r\n',52,'Pesquisadora compartilha resultado de estudos com a populaÃÂ§ÃÂ£o ',2,1,'null','2014-06-18 12:06:44'),(73,'<p style=\"text-align:justify\">A pesquisadora S&iacute;lvia Fran&ccedil;a, da Coordena&ccedil;&atilde;o de Processos Minerais (COPM), participou, no &uacute;ltimo dia 23 de maio, de banca de mestrado na Universidade Federal de Pernambuco como membro avaliador. A disserta&ccedil;&atilde;o que abordou o tema &ldquo;Influ&ecirc;ncia da pr&eacute;-agrega&ccedil;&atilde;o na flocula&ccedil;&atilde;o de part&iacute;culas coloidais de di&oacute;xido de tit&acirc;nio&rdquo; foi defendida no Programa de P&oacute;s-Gradua&ccedil;&atilde;o em Engenharia Mineral por L&iacute;via Campelo de Freitas, sob a orienta&ccedil;&atilde;o do Prof. Carlos Baltar, ex-pesquisador e colaborador do CETEM.&nbsp;&nbsp;</p>\r\n',52,'Pesquisadora do CETEM participa de banca na Universidade Federal de Pernambuco ',2,1,'null','2014-06-18 12:07:12'),(75,'<p><a href=\"https://intranet.cetem.gov.br/index.php?action=doDownload&amp;key=f30b3c024787935673d0ba42405fe5b4\" style=\"box-sizing: border-box; border-collapse: collapse; color: rgba(45, 173, 237, 0.8); outline: 0px; font-family: \'Segoe UI_\', \'Open Sans\', Verdana, Arial, Helvetica, sans-serif; font-size: 13.63636302947998px; line-height: 18.18181800842285px; background-image: initial; background-attachment: initial; background-size: initial; background-origin: initial; background-clip: initial; background-position: initial; background-repeat: initial;\">https://intranet.cetem.gov.br/index.php?action=doDownload&amp;key=f30b3c024787935673d0ba42405fe5b4</a></p>\r\n',53,'ATA',2,1,'null','2014-06-30 15:41:45'),(76,'<p style=\"text-align: justify;\">Nos dias 24 e 25 de julho, o CETEM realiza a sua XXII Jornada de Inicia&ccedil;&atilde;o Cient&iacute;fica com a apresenta&ccedil;&atilde;o oral de 50 trabalhos. Como de costume, o Centro custear&aacute; a vinda ao Rio de Janeiro dos seguintes bolsistas oriundos do NR-ES para que possam expor seus trabalhos: Davi Vargas de Souza, Dghean Zuccon Fazolo, Douglas Bartolete Marcon, Joyce Ara&uacute;jo Maximo da Silva, Leticia Valdo, Pedro Porto Pizetta, Rafaela Farinazo Peloso Alves, Thalissa Pizetta Alto&eacute; e Vagner Moro Ferreira Leit&atilde;o.</p>\r\n\r\n<p style=\"text-align: justify;\">O principal objetivo da JIC &eacute; dar oportunidade aos bolsistas de mostrarem o trabalho que desenvolveram durante o per&iacute;odo de 12 meses de vig&ecirc;ncia da bolsa ofertada pelo Programa Institucional de Bolsas de Inicia&ccedil;&atilde;o Cient&iacute;fica (PIBIC).</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>\r\n<script charset=\"UTF-8\" src=\"chrome://hdv/content/hdv.js\" type=\"application/javascript\"></script>\r\n</p>\r\n',52,'CETEM realiza XXII Jornada de IniciaÃÂ§ÃÂ£o CientÃÂ­fica',2,1,'null','2014-07-02 14:18:16'),(77,'<p style=\"text-align: justify;\">A colaboradora do CETEM Amanda Menezes Ricardo ir&aacute; apresentar dois trabalhos sobre caracteriza&ccedil;&atilde;o e avalia&ccedil;&atilde;o da alterabilidade de rochas presentes no gnaisse facoidal que faz parte das fachadas do Museu Nacional da Quinta e no Pa&ccedil;o Imperial no 54&ordm; Congresso Brasileiro de Qu&iacute;mica, que ocorre entre os dias 03 e 07 de novembro no Centro de Eventos do Paraimar Natal Hotel, em Natal, Rio Grande do Norte.</p>\r\n',52,'CETEM marca presenÃÂ§a no 54ÃÂº Congresso Brasileiro de QuÃÂ­mica',2,1,'null','2014-07-09 14:34:09'),(78,'<p style=\"text-align:justify\">O ge&oacute;logo Jurgen Schnellrath, pesquisador do CETEM respons&aacute;vel pelo Laborat&oacute;rio de Pesquisas Gemol&oacute;gicas (LAPEGE), estar&aacute; em Te&oacute;filo Otoni, Minas Gerais, entre os dias 15 e 1 9 de julho, para participar da Feira Internacional de Pedras Preciosas (FIPP). O CETEM vem participando da maioria das edi&ccedil;&otilde;es da FIPP desde 2004, tendo contado no in&iacute;cio com o apoio log&iacute;stico de GEA (Gems Exporters Association), entidade promotora do evento. Atualmente o LAPEGE conta com o apoio da Universidade do Estado de Minas Gerais (UEMG), com quem o CETEM celebrou recentemente um acordo de coopera&ccedil;&atilde;o t&eacute;cnica. O objetivo da participa&ccedil;&atilde;o no evento &eacute; manter o LAPEGE atualizado sobre a situa&ccedil;&atilde;o do mercado brasileiro de gemas, divulgar as atividades do laborat&oacute;rio e do CETEM e, em contrapartida, oferecer um servi&ccedil;o de identifica&ccedil;&atilde;o gratuito de pedras preciosas aos expositores e visitantes da feira, dando assim maior credibilidade &agrave;s transa&ccedil;&otilde;es comerciais ali realizadas.</p>\r\n',52,'Pesquisador do CETEM participa da Feira Internacional de Pedras Preciosas de TeÃÂ³filo Otoni',2,1,'null','2014-07-09 14:34:44'),(79,'<p style=\"text-align:justify\">A ideia de realiza&ccedil;&atilde;o do projeto intitulado &ldquo;<em>An&aacute;lise do polimento de rochas carbon&aacute;ticas: rela&ccedil;&otilde;es entre as propriedades petrogr&aacute;ficas e o processo de polimento&rdquo;</em>, pelos pesquisadores Thiago Motta Bolonini<em> M. Sc.</em> e Leonardo Luiz Lyrio da Silveira <em>D. Sc.</em>, do N&uacute;cleo Regional do Esp&iacute;rito Santo, foi motivada pela escassez de trabalhos relacionados ao polimento desses materiais p&eacute;treos utilizados para revestimento e visa, a partir de diferentes situa&ccedil;&otilde;es operacionais, e a necessidade de avaliar a influ&ecirc;ncia de tais par&acirc;metros no processo de polimento.</p>\r\n\r\n<p style=\"text-align:justify\">Os principais par&acirc;metros operacionais a serem testados ser&atilde;o a velocidade de rota&ccedil;&atilde;o e carga do sat&eacute;lite, a vaz&atilde;o e a temperatura da &aacute;gua e a temperatura da interface rocha/abrasivo - sendo que para esta pesquisa foram definidos quatro tipos litol&oacute;gicos. A metodologia ter&aacute; como principais ferramentas a an&aacute;lise petrogr&aacute;fica (mineralogia, estado de altera&ccedil;&atilde;o mineral e rela&ccedil;&otilde;es de contato), as an&aacute;lises superficiais diretas (medi&ccedil;&atilde;o de rugosidade, brilho e cor) e indiretas (colora&ccedil;&atilde;o seletiva e an&aacute;lise textural e estrutural quantitativas em imagens digitais) das amostras de rocha visando, em linhas gerais, avaliar as rela&ccedil;&otilde;es entre suas propriedades petrogr&aacute;ficas e o processo de polimento de forma quantitativa.</p>\r\n\r\n<p>&nbsp;</p>\r\n',52,'Pesquisadores do CETEM avaliam relaÃÂ§ÃÂµes entre as propriedades petrogrÃÂ¡ficas e o processo de polimento de mÃÂ¡rmores ',2,1,'null','2014-07-11 12:48:55'),(80,'<p style=\"text-align:justify\">A pesquisadora Zuleica Castilhos participou, entre 10 e 17 de junho, na cidade de Sacramento, nos Estados Unidos, de sess&otilde;es especiais sobre ars&ecirc;nio no meio do ambiente do Congresso Goldschmidt 2014, que &eacute; o principal f&oacute;rum mundial de geoqu&iacute;mica e temas afins.</p>\r\n\r\n<p style=\"text-align:justify\">Zuleica ainda participou do curso p&oacute;s-congresso, intitulado: &ldquo;Environmental Geochemistry, Mineralogy and Microbiology of Arsenic&rdquo;, que abordou bioacessibilidade e biodisponibilidade de ars&ecirc;nio em res&iacute;duos minerais, em fun&ccedil;&atilde;o da&nbsp;caracteriza&ccedil;&atilde;o mineral&oacute;gica e da a&ccedil;&atilde;o microbiana sobre tais res&iacute;duos.</p>\r\n',52,'Pesquisadora do CETEM participa de Congresso Goldschmidt 2014 e de curso pÃÂ³s-congresso, nos Estados Unidos',2,1,'null','2014-07-24 15:51:50'),(81,'<p style=\"text-align:justify\">O pesquisador Jurgen Schnellrath, respons&aacute;vel pelo Laborat&oacute;rio de Pesquisas Gemol&oacute;gicas (LAPEGE), ir&aacute; representar o CETEM no 6&ordm; Simp&oacute;sio de Geologia do Diamante, a ser realizado em Patos de Minas no per&iacute;odo de 03 a 08 de agosto, com o objetivo maior de atualizar seus conhecimentos sobre diversos temas que ser&atilde;o abordados durante o evento. Al&eacute;m de assistir a diversas apresenta&ccedil;&otilde;es sobre a geologia desta importante gema e suas ocorr&ecirc;ncias, tanto a n&iacute;vel nacional como internacional, participar&aacute; tamb&eacute;m da Reuni&atilde;o do F&oacute;rum Brasileiro do Certificado de Kimberley.</p>\r\n\r\n<p style=\"text-align:justify\">Especial aten&ccedil;&atilde;o ser&aacute; dada &agrave;s palestras a serem proferidas por James Shigley, do Departamento de Pesquisas do Gemological Institute Of America (&ldquo;Identification of Treated and Synthetic Diamonds&rdquo; e &ldquo;Causes of Color in Diamonds&rdquo;) e pelo professor Pedro Juchem, da UFRGS (&ldquo;An&aacute;lise Multi-T&eacute;cnicas para Identificar Diamante e Moissanita em Joias&rdquo;). Estas tr&ecirc;s palestras est&atilde;o diretamente ligadas &agrave;s atividades de presta&ccedil;&atilde;o de servi&ccedil;os e pesquisa do LAPEGE e poder&atilde;o trazer importantes informa&ccedil;&otilde;es para a melhoria do seu desempenho nesta &aacute;rea.</p>\r\n\r\n<p style=\"text-align:justify\">Por fim, vale destacar a participa&ccedil;&atilde;o do pesquisador na excurs&atilde;o de campo p&oacute;s-congresso &agrave; Regi&atilde;o Diamant&iacute;fera do Alto Parana&iacute;ba, importante produtora de diamantes no Brasil.</p>\r\n',52,'Pesquisador irÃÂ¡ representar o CETEM no 6ÃÂº SimpÃÂ³sio de Geologia do Diamante',2,1,'null','2014-07-24 15:53:01'),(82,'<div style=\"color: rgb(0, 0, 0); font-family: Tahoma; font-size: 13.63636302947998px; line-height: normal; margin-top: 14pt; margin-bottom: 0px;\">O CETEM realizar&aacute; na pr&oacute;xima sexta feira, 08 de agosto, em seu audit&oacute;rio, um evento para recepcionar os novos bolsistas de inicia&ccedil;&atilde;o cient&iacute;fica.</div>\r\n\r\n<div style=\"color: rgb(0, 0, 0); font-family: Tahoma; font-size: 13.63636302947998px; line-height: normal; margin-top: 14pt; margin-bottom: 0px;\">O diretor do Centro, Dr. Fernando Lins, far&aacute; abertura do evento recepcionado os BICs. Logo ap&oacute;s, os integrantes da Comit&ecirc; Interno de Inicia&ccedil;&atilde;o Cient&iacute;fica do CETEM (CIBIC) far&atilde;o uma exposi&ccedil;&atilde;o sobre as atividades que s&atilde;o desenvolvidos em cada coordena&ccedil;&atilde;o.</div>\r\n\r\n<div style=\"color: rgb(0, 0, 0); font-family: Tahoma; font-size: 13.63636302947998px; line-height: normal; margin-top: 14pt; margin-bottom: 0px;\">Em seguida, o coordenador do CIBIC, Roberto Carlos da Concei&ccedil;&atilde;o Ribeiro, far&aacute; uma apresenta&ccedil;&atilde;o sobre o Programa de Inicia&ccedil;&atilde;o Cient&iacute;fica abordando passo a passo seu funcionamento &ndash; necessidade da elabora&ccedil;&atilde;o de trabalho escrito, apresenta&ccedil;&atilde;o oral, banca de avalia&ccedil;&atilde;o e pr&ecirc;mios ser&atilde;o alguns dos temas tratados. O servidor Ary Caldas Pinheiro ministrar&aacute; uma palestra sobre Biosseguran&ccedil;a em laborat&oacute;rio. No final do evento, os novos BICs ainda participar&atilde;o de um visita guiada pelas depend&ecirc;ncias dos CETEM.</div>\r\n',52,'CETEM dÃÂ¡ boas vindas a novos integrantes do Programa de IniciaÃÂ§ÃÂ£o CientÃÂ­fica',2,1,'null','2014-08-05 12:40:08'),(83,'<div style=\"color: rgb(0, 0, 0); font-family: Tahoma; font-size: 13.63636302947998px; line-height: normal; margin: 14pt 0px 0px; text-align: justify;\"><span style=\"font-size:12pt\">A 66&ordf; Reuni&atilde;o Anual da SBPC (Sociedade Brasileira para o Progresso da Ci&ecirc;ncia) ocorreu esse ano entre os dias 22 e 27 de julho, no campus da Universidade Federal do Acre (UFAC), em Rio Branco, AC. O tema desta edi&ccedil;&atilde;o foi &quot;Ci&ecirc;ncia e Tecnologia em uma Amaz&ocirc;nia sem Fronteiras&quot;.</span></div>\r\n\r\n<div style=\"color: rgb(0, 0, 0); font-family: Tahoma; font-size: 13.63636302947998px; line-height: normal; margin: 14pt 0px 0px; text-align: justify;\"><span style=\"font-size:12pt\">O CETEM foi representado pela pesquisadora Zuleica Castilhos, com a apresenta&ccedil;&atilde;o oral de trabalho intitulado &ldquo;Merc&uacute;rio em Peixes da Amaz&ocirc;nia: conhecer para prevenir&rdquo;.&nbsp;</span></div>\r\n\r\n<div style=\"color: rgb(0, 0, 0); font-family: Tahoma; font-size: 13.63636302947998px; line-height: normal; margin: 14pt 0px 0px; text-align: justify;\"><span style=\"font-size:12pt\">A reuni&atilde;o anual da SBPC, que &eacute; realizada desde 1948, &eacute; composta por confer&ecirc;ncias, simp&oacute;sios, mesas-redondas, encontros, sess&otilde;es especiais, minicursos e sess&otilde;es de p&ocirc;steres, e contou com a participa&ccedil;&atilde;o de representantes de sociedades cient&iacute;ficas, autoridades e gestores do sistema nacional de ci&ecirc;ncia e tecnologia.&nbsp;</span></div>\r\n',52,'A 66ÃÂª ReuniÃÂ£o Anual da SBPC: Pesquisadora apresenta trabalho sobre contaminaÃÂ§ÃÂ£o por mercÃÂºrio ',2,1,'null','2014-08-12 15:19:48'),(84,'<p style=\"text-align: justify;\">O pesquisador Julio C&eacute;sar Guedes Correia estar&aacute; em Petr&oacute;polis, no per&iacute;odo de 18 a 22 de agosto, para participar do VII Encontro de Modelagem Molecular em Sistemas Biol&oacute;gicos, no Laborat&oacute;rio Nacional de Computa&ccedil;&atilde;o Cient&iacute;fica (LNCC).</p>\r\n\r\n<p style=\"text-align: justify;\">O Dr. Julio, que defendeu sua tese de doutorado na &aacute;rea, aproveitar&aacute; a ocasi&atilde;o para discutir com o Dr. Laurent Dardenne, do LNCC, a utiliza&ccedil;&atilde;o de Modelagem Molecular em conjunto pelas duas institui&ccedil;&otilde;es, com destaque para programas voltados para a &aacute;rea mineral.</p>\r\n\r\n<p style=\"text-align: justify;\">O VII Encontro de Modelagem Molecular em Sistemas Biol&oacute;gicos est&aacute; em sua s&eacute;tima edi&ccedil;&atilde;o e conta com a participa&ccedil;&atilde;o de estudantes e pesquisadores interessados em &aacute;reas relacionadas &agrave; modelagem molecular computacional, entre outros assuntos relacionados. Durante o evento, ser&atilde;o ministradas palestras e minicursos te&oacute;ricos e pr&aacute;ticos.</p>\r\n',52,'Pesquisador do CETEM participa de VII Encontro de Modelagem Molecular em Sistemas BiolÃÂ³gicos',2,1,'null','2014-08-14 16:13:56'),(85,'<p style=\"text-align: justify;\"><span style=\"color:black; font-family:calibri,sans-serif; font-size:11.0pt\">O Instituto de Radioprote&ccedil;&atilde;o e Dosimetria realiza, entre os dias 18 e 20 de agosto, como apoio da SBBN (Sociedade Brasileira de Bioci&ecirc;ncias Nucleares), o <em>Simp&oacute;sio Min&eacute;rios &amp; Radioatividade &ndash; NORM: Gerenciamento do Ponto de Vista da Prote&ccedil;&atilde;o Radiol&oacute;gica</em>. </span></p>\r\n\r\n<p style=\"text-align: justify;\"><span style=\"color:black; font-family:tahoma,sans-serif; font-size:10.0pt\">&nbsp;</span><span style=\"color:black; font-family:calibri,sans-serif; font-size:11.0pt\">Os pesquisadores do CETEM Ronaldo Luiz Correa dos Santos, Ysrael Marrero Vera, Maria Alice Cabral de Goes e Otavio da Fonseca Martins Gomes acompanhar&atilde;o os f&oacute;runs de discuss&atilde;o em busca de novos conhecimentos em temas como: </span><span style=\"color:#1F497D; font-family:calibri,sans-serif; font-size:11.0pt\">d</span><span style=\"color:black; font-family:calibri,sans-serif; font-size:11.0pt\">esafios para regulamenta&ccedil;&atilde;o; </span><span style=\"color:#1F497D; font-family:calibri,sans-serif; font-size:11.0pt\">d</span><span style=\"color:black; font-family:calibri,sans-serif; font-size:11.0pt\">eposi&ccedil;&atilde;o e minimiza&ccedil;&atilde;o de rejeitos; </span><span style=\"color:#1F497D; font-family:calibri,sans-serif; font-size:11.0pt\">i</span><span style=\"color:black; font-family:calibri,sans-serif; font-size:11.0pt\">mplementa&ccedil;&atilde;o de plano de prote&ccedil;&atilde;o da for&ccedil;a de trabalho; </span><span style=\"color:#1F497D; font-family:calibri,sans-serif; font-size:11.0pt\">c</span><span style=\"color:black; font-family:calibri,sans-serif; font-size:11.0pt\">ontroles ocupacional e ambiental; e </span><span style=\"color:#1F497D; font-family:calibri,sans-serif; font-size:11.0pt\">n</span><span style=\"color:black; font-family:calibri,sans-serif; font-size:11.0pt\">ecessidade de treinamento e capacita&ccedil;&atilde;o. </span></p>\r\n\r\n<p style=\"text-align: justify;\"><span style=\"color:black; font-family:tahoma,sans-serif; font-size:10.0pt\">&nbsp;</span><span style=\"color:black; font-family:calibri,sans-serif; font-size:11.0pt\">O evento tem como objetivo criar um espa&ccedil;o para que profissionais de prote&ccedil;&atilde;o radiol&oacute;gica, de ind&uacute;strias que em decorr&ecirc;ncia de suas atividades produzem materiais radioativos de ocorr&ecirc;ncia natural, de &oacute;rg&atilde;os reguladores nacionais e internacionais, de universidades e de centros de pesquisa possam trocar ideias, experi&ecirc;ncias e t&eacute;cnicas de atua&ccedil;&atilde;o.</span></p>\r\n\r\n<p><span style=\"color:black; font-family:tahoma,sans-serif; font-size:10.0pt\">&nbsp;</span></p>\r\n',52,'Pesquisadores do CETEM acompanham SimpÃÂ³sio MinÃÂ©rios & Radioatividade ',2,1,'null','2014-08-15 13:01:37');
